import{_ as e,o as s,c as a,a as t}from"./app.014522ac.js";const y=JSON.parse('{"title":"Guide to Editing the Yoahtl Website","description":"","frontmatter":{},"headers":[{"level":2,"title":"General Goals","slug":"general-goals","link":"#general-goals","children":[]},{"level":2,"title":"Requirements","slug":"requirements","link":"#requirements","children":[]},{"level":2,"title":"How to edit a page","slug":"how-to-edit-a-page","link":"#how-to-edit-a-page","children":[]},{"level":2,"title":"Creating a page","slug":"creating-a-page","link":"#creating-a-page","children":[]},{"level":2,"title":"WTF is Git?","slug":"wtf-is-git","link":"#wtf-is-git","children":[]}],"relativePath":"editGuide.md","lastUpdated":1665843048000}'),n={name:"editGuide.md"},o=t(`<h1 id="guide-to-editing-the-yoahtl-website" tabindex="-1">Guide to Editing the Yoahtl Website <a class="header-anchor" href="#guide-to-editing-the-yoahtl-website" aria-hidden="true">#</a></h1><h2 id="general-goals" tabindex="-1">General Goals <a class="header-anchor" href="#general-goals" aria-hidden="true">#</a></h2><p>A list of the current goals and objectives for the website can be found on the <a href="https://github.com/orgs/CivYoahtl/projects/3/views/1" target="_blank" rel="noreferrer">GitHub Project</a>.</p><h2 id="requirements" tabindex="-1">Requirements <a class="header-anchor" href="#requirements" aria-hidden="true">#</a></h2><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>If you only want to do a quick edit, and don&#39;t need to preview your changes, you don&#39;t need the following requirements. Using a simple text editor or GitHub&#39;s website to edit the Markdown files is fine.</p></div><ul><li><a href="https://nodejs.org/en/" target="_blank" rel="noreferrer">Node.js</a> (Use lts version)</li><li><a href="https://yarnpkg.com/getting-started/install" target="_blank" rel="noreferrer">Yarn</a> (Only install don&#39;t init or anything else)</li></ul><h2 id="how-to-edit-a-page" tabindex="-1">How to edit a page <a class="header-anchor" href="#how-to-edit-a-page" aria-hidden="true">#</a></h2><p>Its really simple. All the content for the site is in the <code>docs</code> folder and are <code>Markdown</code> files. (If you need to learn Markdown, use the <a href="https://www.markdownguide.org/" target="_blank" rel="noreferrer">Markdown Guide</a>.) Then, just add the content you want to the file. If you want to use extra Markdown features, refer to <a href="https://vitepress.vuejs.org/guide/markdown.html" target="_blank" rel="noreferrer">Vitepress&#39;s Markdown Extensions</a>.</p><h2 id="creating-a-page" tabindex="-1">Creating a page <a class="header-anchor" href="#creating-a-page" aria-hidden="true">#</a></h2><p>To make a new page on the website, you need to decide on which section it falls under, the make the file under that folder in the <code>docs</code> folder. Make sure to name the file in <a href="https://en.wikipedia.org/wiki/Camel_case" target="_blank" rel="noreferrer">Camel Case</a> similar to what you intend to title the page. (If the title is long, you can shorten the file name.)</p><p>For example the title of <code>The Great War</code> would become the filename of <code>greatWar.md</code>. The reason the <code>.md</code> is added to the end of the name, is so that programs know that the file is a Markdown file.</p><p>Now that you have made the file, its time to make it accessible via the sidebar. Open up the <code>config.js</code> file in the <code>docs/.vitepress</code> folder. Scroll down until you see the <code>sidebar</code> section, then scroll until you see the section you put the file under. Then within that section, find an applicable sub section to put a link to the page.</p><p>For example a sub section may generically look like:</p><div class="language-json"><button class="copy"></button><span class="lang">json</span><pre><code><span class="line"><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#A6ACCD;">    text</span><span style="color:#89DDFF;">:</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">Sub section</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#A6ACCD;">    items</span><span style="color:#89DDFF;">:</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">[</span></span>
<span class="line"><span style="color:#A6ACCD;">        </span><span style="color:#89DDFF;">{</span><span style="color:#A6ACCD;"> text</span><span style="color:#89DDFF;">:</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">First link</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">,</span><span style="color:#A6ACCD;"> link</span><span style="color:#89DDFF;">:</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">/FOLDER/fileName</span><span style="color:#89DDFF;">&quot;</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">},</span></span>
<span class="line"><span style="color:#A6ACCD;">    </span><span style="color:#89DDFF;">],</span></span>
<span class="line"><span style="color:#89DDFF;">}</span><span style="color:#A6ACCD;">,</span></span>
<span class="line"></span></code></pre></div><p>Now for example if you wanted to add a file under the <code>culture</code> section, with a full filename of <code>test.md</code>, and a title of <code>Test</code> it would be:</p><div class="language-json"><button class="copy"></button><span class="lang">json</span><pre><code><span class="line"><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#A6ACCD;">    text</span><span style="color:#89DDFF;">:</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">Great Sub Section Name</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#A6ACCD;">    items</span><span style="color:#89DDFF;">:</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">[</span></span>
<span class="line"><span style="color:#A6ACCD;">        </span><span style="color:#89DDFF;">{</span><span style="color:#A6ACCD;"> text</span><span style="color:#89DDFF;">:</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">Test</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">,</span><span style="color:#A6ACCD;"> link</span><span style="color:#89DDFF;">:</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">/culture/test</span><span style="color:#89DDFF;">&quot;</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">},</span></span>
<span class="line"><span style="color:#A6ACCD;">    </span><span style="color:#89DDFF;">],</span></span>
<span class="line"><span style="color:#89DDFF;">}</span><span style="color:#A6ACCD;">,</span></span>
<span class="line"></span></code></pre></div><p>Now notice how the path for <code>link</code> is similar to the structure of how the files are laid out in the <code>docs</code> folder? Thats because your telling the website to go into the <code>culture</code> folder and find the file with the of <code>test</code>. Also notice how the <code>.md</code> wasn&#39;t included. Thats because <strong>only</strong> <code>.md</code> files should be placed within those folders, and it assumes as such.</p><h2 id="wtf-is-git" tabindex="-1">WTF is Git? <a class="header-anchor" href="#wtf-is-git" aria-hidden="true">#</a></h2><p>You can learn more about Git &amp; Github on <a href="https://github.com/git-guides" target="_blank" rel="noreferrer">Github&#39;s Git Guide</a>.</p>`,19),l=[o];function r(i,p,c,d,h,u){return s(),a("div",null,l)}const g=e(n,[["render",r]]);export{y as __pageData,g as default};
